/* ========================================================================== */
  /* PAGE INTERACTIONS (Scroll Reveal & Counters)                               */
  /* ========================================================================== */
  (function () {
    'use strict';

    /* ── Scroll-Reveal (IntersectionObserver) ── */
    const revealEls = document.querySelectorAll('.fade-up, .fade-in');
    if (revealEls.length) {
      const obs = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              entry.target.classList.add('visible');
              obs.unobserve(entry.target);
            }
          });
        },
        { threshold: 0.12 }
      );
      revealEls.forEach((el) => obs.observe(el));
    }

    /* ── Animated Counter for stat-num ── */
    function animateCounter(el) {
      const raw    = el.textContent.trim();
      const suffix = raw.replace(/[0-9.]/g, '');
      const numStr = raw.replace(/[^0-9.]/g, '');
      const target = parseFloat(numStr);
      if (isNaN(target) || target === 0) return;

      const duration = 1600;
      const start    = performance.now();
      function step(now) {
        const progress = Math.min((now - start) / duration, 1);
        const eased    = 1 - Math.pow(1 - progress, 3);

        let displayNum = (eased * target);
        // Handle decimals like 8.4k vs integers
        if (raw.includes('.')) {
          el.textContent = displayNum.toFixed(1) + suffix;
        } else {
          el.textContent = Math.floor(displayNum) + suffix;
        }

        if (progress < 1) requestAnimationFrame(step);
      }
      requestAnimationFrame(step);
    }

    const statNums = document.querySelectorAll('.stat-num');
    if (statNums.length) {
      const cObs = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              animateCounter(entry.target);
              cObs.unobserve(entry.target);
            }
          });
        },
        { threshold: 0.5 }
      );
      statNums.forEach((el) => cObs.observe(el));
    }

  })();
